// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/*
 * 🎓 EJERCICIO 1: Estados de un Pedido E-Commerce
 *
 * Modela un ciclo restrictivo para un pedido en línea usando un Enum.
 * No es necesario crear funciones.
 * 
 * 1. Crea un Enum llamado `EstadoPedido` con los siguientes valores:
 *    "Creado", "Pagado", "EnCamino" y "Entregado".
 * 
 * 2. Luego, declara una variable pública llamada `miPedido` del tipo `EstadoPedido`
 *    e inicialízala con el estado `EnCamino`.
 */

contract EjerciciosEnums {
    // 📝 Escribe tu código aquí debajo
    enum EstadoPedido {
        Creado,
        Pagado,
        EnCamino,
        Entregado
    }

    EstadoPedido public miPedido = EstadoPedido.EnCamino;
}

